// ── AAA 성적 카드 ────────────────────────────────────────────────────────────
// 공통 테이블 컴포넌트
function DataTable({ headers, rows, highlightCol }) {
  if (!rows || !rows.length) return null;
  return (
    <div style={{overflowX:"auto"}}>
      <table style={{width:"100%",borderCollapse:"collapse",fontSize:11}}>
        <thead>
          <tr>
            {headers.map((h,i)=>(
              <th key={i} style={{padding:"5px 6px",background:"#0a1628",color:i===highlightCol?"#f59e0b":"#64748b",fontWeight:700,textAlign:"center",borderBottom:"1px solid #1e293b",whiteSpace:"nowrap"}}>
                {h}
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {rows.map((row,ri)=>(
            <tr key={ri} style={{background:ri%2===0?"#0d1b3e":"#0a1628"}}>
              {row.map((cell,ci)=>(
                <td key={ci} style={{padding:"5px 6px",textAlign:"center",color:ci===0?"#94a3b8":"#e2e8f0",fontWeight:ci===0?600:400,borderBottom:"1px solid rgba(255,255,255,0.03)",whiteSpace:"nowrap"}}>
                  {cell??"-"}
                </td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

function AAASection({ title, color, children }) {
  return (
    <div style={{background:"#0d1b2e",borderRadius:10,overflow:"hidden",border:`1px solid ${color}22`}}>
      <div style={{background:color,color:"#fff",padding:"7px 14px",fontWeight:800,fontSize:12}}>{title}</div>
      <div style={{padding:10}}>{children}</div>
    </div>
  );
}

function AAABatStat({ d, year }) {
  if (!d) return <div style={{color:"#334155",fontSize:11,textAlign:"center",padding:6}}>{year} 데이터 없음</div>;
  return (
    <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:5}}>
      <StatBadge label="PA"  value={d.pa}/>
      <StatBadge label="H"   value={d.h}/>
      <StatBadge label="HR"  value={d.hr} highlight={d.hr>0}/>
      <StatBadge label="AVG" value={d.avg??"-"} highlight={d.avg&&parseFloat(d.avg)>0.3}/>
      <StatBadge label="OBP" value={d.obp??"-"} highlight={d.obp&&parseFloat(d.obp)>0.35}/>
      <StatBadge label="SLG" value={d.slg??"-"} highlight={d.slg&&parseFloat(d.slg)>0.45}/>
      <StatBadge label="K%"  value={d.kpct??"-"} highlight={d.kpct&&parseFloat(d.kpct)<15}/>
      <StatBadge label="BB%" value={d.bbpct??"-"} highlight={d.bbpct&&parseFloat(d.bbpct)>10}/>
    </div>
  );
}

function AAAPitStat({ d, year, apiStat }) {
  if (!d) return <div style={{color:"#334155",fontSize:11,textAlign:"center",padding:6}}>{year} 데이터 없음</div>;
  const ip   = apiStat?.inningsPitched ?? null;
  const era  = apiStat?.era  ?? null;
  const whip = apiStat?.whip ?? null;
  const g    = apiStat?.gamesPitched ?? null;
  const w    = apiStat?.wins   ?? null;
  const l    = apiStat?.losses ?? null;
  const wl   = w != null && l != null ? `${w}-${l}` : "-";
  const hrA  = apiStat?.homeRuns ?? d.hr;
  return (
    <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:5}}>
      <StatBadge label="G"      value={g ?? "-"}/>
      <StatBadge label="IP"     value={ip  != null ? fmt1(ip)  : "-"}/>
      <StatBadge label="W-L"    value={wl}/>
      <StatBadge label="ERA"    value={era  != null ? fmt2(era)  : "-"} highlight={era  != null && parseFloat(era)  < 3}/>
      <StatBadge label="WHIP"   value={whip != null ? fmt2(whip) : "-"} highlight={whip != null && parseFloat(whip) < 1}/>
      <StatBadge label="HR허용" value={hrA ?? "-"}/>
      <StatBadge label="K%"     value={d.kpct??"-"}  highlight={d.kpct&&parseFloat(d.kpct)>25}/>
      <StatBadge label="BB%"    value={d.bbpct??"-"}/>
    </div>
  );
}

function AAAYearBlock({ label, children }) {
  return (
    <div>
      <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:6}}>
        <span style={{fontSize:11,fontWeight:800,color:"#34d399"}}>{label}</span>
      </div>
      {children}
    </div>
  );
}

function AAAStatsCard({ player, apiData }) {
  if (!player.mlbId) return null;
  const id = String(player.mlbId);
  const p = player.isPitcher;
  const entry = p ? AAA_P[id] : AAA_B[id];
  if (!entry) return null;

  const stat = entry.stat || {};
  const has24 = stat.y24 != null;
  const has25 = stat.y25 != null;
  if (!has24 && !has25) return null;

  return (
    <div style={{display:"flex",flexDirection:"column",gap:12}}>

      {/* 투수/타자 성적 */}
      <AAASection title="🌿 AAA 성적" color="#065f46">
        <div style={{display:"flex",flexDirection:"column",gap:12}}>
          {has25 && <AAAYearBlock label="2025">{p
            ? <AAAPitStat d={stat.y25} year="2025" apiStat={apiData?.aaaP2025}/>
            : <AAABatStat d={stat.y25} year="2025"/>}
          </AAAYearBlock>}
          {has24 && has25 && <div style={{borderTop:"1px solid rgba(255,255,255,0.05)"}}/>}
          {has24 && <AAAYearBlock label="2024">{p
            ? <AAAPitStat d={stat.y24} year="2024" apiStat={apiData?.aaaP2024}/>
            : <AAABatStat d={stat.y24} year="2024"/>}
          </AAAYearBlock>}
        </div>
      </AAASection>

      {/* 투수: 구종트래킹 */}
      {p && (() => {
        const pitch = entry.pitch || {};
        const pp25 = pitch.y25, pp24 = pitch.y24;
        if (!pp25 && !pp24) return null;
        const headers = ["구종","구사율","투구수","평균구속","최고구속","회전수","회전축","수직무브","수평무브","릴리스높이","릴리스사이드","익스텐션","S%","헛스윙%","피안타율"];
        const makeRows = (arr) => arr ? arr.map(p=>[
          p.name, p.rate, p.pitches, p.avgV, p.maxV, p.spin,
          p.axis, p.vmov, p.hmov, p.rh, p.rs, p.ext, p.spct, p.whiff, p.avg
        ]) : null;
        return (
          <AAASection title="⚾ AAA 구종 트래킹" color="#1e40af">
            <div style={{display:"flex",flexDirection:"column",gap:10}}>
              {pp25 && <><div style={{fontSize:11,fontWeight:800,color:"#60a5fa",marginBottom:4}}>2025</div><DataTable headers={headers} rows={makeRows(pp25)}/></>}
              {pp24 && pp25 && <div style={{borderTop:"1px solid rgba(255,255,255,0.05)",margin:"4px 0"}}/>}
              {pp24 && <><div style={{fontSize:11,fontWeight:800,color:"#475569",marginBottom:4}}>2024</div><DataTable headers={headers} rows={makeRows(pp24)}/></>}
            </div>
          </AAASection>
        );
      })()}

      {/* 타자: 타구트래킹 */}
      {!p && (() => {
        const track = entry.track || {};
        const t25 = track.y25, t24 = track.y24;
        if (!t25 && !t24) return null;
        const headers = ["인플레이","평균타구속도","최고타구속도","발사각","하드힛%","배럴%","정타%","GB%","FB%","LD%"];
        const makeRows = (t) => t ? [[
          t.ip, t.avgEV, t.maxEV, t.la,
          t.hard, t.barrel, t.solid, t.gb, t.fb, t.ld
        ]] : null;
        return (
          <AAASection title="🎯 AAA 타구 트래킹" color="#1e40af">
            <div style={{display:"flex",flexDirection:"column",gap:10}}>
              {t25 && <><div style={{fontSize:11,fontWeight:800,color:"#60a5fa",marginBottom:4}}>2025</div><DataTable headers={headers} rows={makeRows(t25)}/></>}
              {t24 && t25 && <div style={{borderTop:"1px solid rgba(255,255,255,0.05)",margin:"4px 0"}}/>}
              {t24 && <><div style={{fontSize:11,fontWeight:800,color:"#475569",marginBottom:4}}>2024</div><DataTable headers={headers} rows={makeRows(t24)}/></>}
            </div>
          </AAASection>
        );
      })()}

      {/* 타자: 접근법 */}
      {!p && (() => {
        const app = entry.app || {};
        const a25 = app.y25, a24 = app.y24;
        if (!a25 && !a24) return null;
        const headers = ["타석당투구수","컨택%","헛스윙%","헛스윙%(2S)","Zone%","존반응%","존컨택%","존밖반응%","존밖컨택%"];
        const makeRows = (a) => a ? [[
          a.pitPerPA, a.con, a.whiff, a.whiff2s, a.zone,
          a.zswing, a.zcon, a.oswing, a.ocon
        ]] : null;
        return (
          <AAASection title="🧠 AAA 타격 접근법" color="#6d28d9">
            <div style={{display:"flex",flexDirection:"column",gap:10}}>
              {a25 && <><div style={{fontSize:11,fontWeight:800,color:"#a78bfa",marginBottom:4}}>2025</div><DataTable headers={headers} rows={makeRows(a25)}/></>}
              {a24 && a25 && <div style={{borderTop:"1px solid rgba(255,255,255,0.05)",margin:"4px 0"}}/>}
              {a24 && <><div style={{fontSize:11,fontWeight:800,color:"#475569",marginBottom:4}}>2024</div><DataTable headers={headers} rows={makeRows(a24)}/></>}
            </div>
          </AAASection>
        );
      })()}
    </div>
  );
}



